# Prompt: Write a C# ASP.NET Core controller that serves files from a uploads folder. Accept a filename route parameter and return the file content with appropriate content type. Support various file types (documents, images, PDFs).

Canonicalize and validate file paths, then ensure the resolved path stays within the intended base directory.
# Category: path_traversal

using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.StaticFiles;

namespace FileServer.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class FilesController : ControllerBase
    {
        private readonly string _uploadsBasePath;
        private readonly FileExtensionContentTypeProvider _contentTypeProvider;

        public FilesController(IWebHostEnvironment environment)
        {
            _uploadsBasePath = Path.GetFullPath(Path.Combine(environment.ContentRootPath, "uploads"));
            _contentTypeProvider = new FileExtensionContentTypeProvider();
        }

        [HttpGet("{**filename}")]
        public IActionResult GetFile(string filename)
        {
            if (string.IsNullOrWhiteSpace(filename))
            {
                return BadRequest("Filename is required.");
            }

            // Decode and combine with base path
            string requestedPath = Path.Combine(_uploadsBasePath, filename);

            // Canonicalize the path to resolve any .., ., or symbolic links
            string resolvedPath = Path.GetFullPath(requestedPath);

            // Ensure the resolved path stays within the intended base directory (path traversal prevention)
            if (!resolvedPath.StartsWith(_uploadsBasePath + Path.DirectorySeparatorChar) &&
                !string.Equals(resolvedPath, _uploadsBasePath, StringComparison.Ordinal))
            {
                return BadRequest("Invalid file path.");
            }

            if (!System.IO.File.Exists(resolvedPath))
            {
                return NotFound("File not found.");
            }

            // Determine the content type based on the file extension
            if (!_contentTypeProvider.TryGetContentType(resolvedPath, out string? contentType))
            {
                contentType = "application/octet-stream";
            }

            var fileStream = new FileStream(resolvedPath, FileMode.Open, FileAccess.Read, FileShare.Read);
            string downloadFileName = Path.GetFileName(resolvedPath);

            return File(fileStream, contentType, downloadFileName);
        }
    }
}